/// <summary>
/// Retrieves the item name from the InventTable based on the ItemId in the current record.
/// </summary>
/// <returns>
/// The item name as a display method of type ItemFreeTxt.
/// </returns>
public display ItemFreeTxt vendnameRateCard()
{
    return InventTable::find(this.ItemId).itemName();
}
